import React, { useEffect, useRef } from 'react';
import styled from 'styled-components';

const MapContainer = styled.div`
  position: relative;
  height: 200px;
  background: #1a1a1a;
  z-index: 1;

  .leaflet-container {
    width: 100%;
    height: 100%;
    background: #1a1a1a;
    border-radius: 0;
  }

  &::after {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(180deg, transparent 60%, rgba(26,26,26,0.85) 100%);
    pointer-events: none;
    z-index: 2;
  }

  .leaflet-tile-pane { filter: brightness(0.85) saturate(0.7); }
  .leaflet-control-attribution { font-size: 9px !important; opacity: 0.5; }
`;

export default function EventMap({ startLoc, endLoc }) {
  const containerRef = useRef(null);
  const mapRef = useRef(null);

  useEffect(() => {
    if (!containerRef.current || !startLoc || !window.L) return;

    // Defer slightly so the container is laid out in the DOM
    const timer = setTimeout(() => {
      if (!containerRef.current) return;
      if (mapRef.current) { mapRef.current.remove(); mapRef.current = null; }

      const L = window.L;
      const map = L.map(containerRef.current, {
        zoomControl: false,
        attributionControl: false,
        scrollWheelZoom: false,
        dragging: false,
        tap: false,
      }).setView([startLoc.lat, startLoc.lng], 13);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
        subdomains: 'abcd',
        maxZoom: 19,
      }).addTo(map);

      const yolkIcon = L.divIcon({
        className: 'pin-yolk',
        iconSize: [18, 18],
        iconAnchor: [9, 9],
      });

      L.marker([startLoc.lat, startLoc.lng], { icon: yolkIcon }).addTo(map);

      const hasDiffEnd = endLoc &&
        (endLoc.lat !== startLoc.lat || endLoc.lng !== startLoc.lng);

      if (hasDiffEnd) {
        L.marker([endLoc.lat, endLoc.lng], { icon: yolkIcon }).addTo(map);
        L.polyline(
          [[startLoc.lat, startLoc.lng], [endLoc.lat, endLoc.lng]],
          { color: '#FFC72C', weight: 3, opacity: 0.7, dashArray: '6 8' }
        ).addTo(map);
        map.fitBounds(
          [[startLoc.lat, startLoc.lng], [endLoc.lat, endLoc.lng]],
          { padding: [40, 40] }
        );
      }

      mapRef.current = map;
    }, 30);

    return () => {
      clearTimeout(timer);
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, [startLoc, endLoc]);

  return <MapContainer ref={containerRef} />;
}
